firmware_template.source:
#include "bme680.h"
#include <Wire.h>
static Adafruit_BME680 bme;
static float _temp=0,_hum=0,_pres=0,_gas=0;
static unsigned long _last=0;
void bme680_setup() {
  Wire.begin();
  if (!bme.begin(0x77)) { Serial.println("[bme680] Init failed!"); return; }
  bme.setTemperatureOversampling(BME680_OS_8X);
  bme.setHumidityOversampling(BME680_OS_2X);
  bme.setPressureOversampling(BME680_OS_4X);
  bme.setIIRFilterSize(BME680_FILTER_SIZE_3);
  bme.setGasHeater(320, 150);
  Serial.println("[bme680] OK");
}
void bme680_loop() {
  if (millis()-_last < 3000) return;
  _last = millis();
  if (bme.performReading()) {
    _temp = bme.temperature;
    _hum = bme.humidity;
    _pres = bme.pressure / 100.0F;
    _gas = bme.gas_resistance / 1000.0F;
    Serial.printf("[bme680] T=%.1fC H=%.0f%% P=%.0fhPa G=%.1fkOhm\n",_temp,_hum,_pres,_gas);
  }
}
float bme680_get_temperature(){return _temp;}
float bme680_get_humidity(){return _hum;}
float bme680_get_pressure(){return _pres;}
float bme680_get_gas(){return _gas;}
